mapper.update:
/* ProductMapper.updateProduct */
UPDATE PRODUCT
   SET CAT_SN            = #{catSn},
       PRD_NM            = #{prdNm},
       PRD_CN            = #{prdCn},
       PRD_STATUS_CD     = #{prdStatusCd},
       PRD_START_AMT     = #{prdStartAmt},
       PRD_IBY_AMT       = #{prdIbyAmt},
       PRD_TRD_METHOD_CD = #{prdTrdMethodCd},
       PRD_UPDT_ID       = #{prdUpdtId}
 WHERE PRD_SN    = #{prdSn}
   AND USR_SN    = #{usrSn}
   AND PRD_USE_YN = 'Y'

mapper.select:
/* ProductMapper.findProductEntityById */
SELECT PRD_SN, USR_SN, CAT_SN, PRD_NM, PRD_CN, PRD_STATUS_CD,
       PRD_START_AMT, PRD_IBY_AMT, PRD_TRD_METHOD_CD, PRD_USE_YN,
       PRD_REG_DT, PRD_UPDT_DT, PRD_REG_ID, PRD_UPDT_ID
  FROM PRODUCT
 WHERE PRD_SN = #{prdSn}

mapper.update:
/* ProductMapper.incrementViewCount */
UPDATE PRODUCT
   SET PRD_VIEW_CNT = PRD_VIEW_CNT + 1
 WHERE PRD_SN = #{prdSn}
   AND PRD_USE_YN = 'Y'

/* ProductMapper.deleteProduct */
UPDATE PRODUCT
   SET PRD_USE_YN    = 'N',
       PRD_STATUS_CD = 'PRDC0004',
       PRD_UPDT_ID   = CAST(#{usrSn} AS CHAR)
 WHERE PRD_SN = #{prdSn}
   AND USR_SN = #{usrSn}
